import math

import numpy as np


def exact_match(prediction, expected):
    """Exact match score."""
    return 1.0 if prediction.strip().lower() == expected.strip().lower() else 0.0


def token_f1(prediction, expected):
    """Token-level F1 over whitespace-split, lowercased token sets."""
    pred_tokens = set(prediction.lower().split())
    exp_tokens = set(expected.lower().split())
    if not pred_tokens or not exp_tokens:
        return 0.0
    common = pred_tokens & exp_tokens
    precision = len(common) / len(pred_tokens)
    recall = len(common) / len(exp_tokens)
    if precision + recall == 0:
        return 0.0
    return 2 * (precision * recall) / (precision + recall)


def perplexity(log_probs):
    """Perplexity from per-token log probabilities."""
    if len(log_probs) == 0:
        return float("inf")
    arr = np.asarray(log_probs, dtype=float)
    avg_neg_log_prob = -float(np.mean(arr))
    return float(np.exp(avg_neg_log_prob))


def expected_score(rating_a, rating_b):
    """Expected win probability of player A against player B."""
    return 1.0 / (1.0 + 10 ** ((rating_b - rating_a) / 400))


def update_elo(rating_a, rating_b, outcome, k=32):
    """Update both ELO ratings after one match."""
    ea = expected_score(rating_a, rating_b)
    eb = 1.0 - ea
    if outcome == "a":
        sa, sb = 1.0, 0.0
    elif outcome == "b":
        sa, sb = 0.0, 1.0
    elif outcome == "tie":
        sa, sb = 0.5, 0.5
    else:
        raise ValueError("outcome must be 'a', 'b', or 'tie'")
    new_a = rating_a + k * (sa - ea)
    new_b = rating_b + k * (sb - eb)
    return new_a, new_b
